# JavaScript Debounce Function

Here's a comprehensive implementation with explanations:

## Basic Implementation

```javascript
function debounce(func, delay) {
  let timeoutId;

  return function(...args) {
    // Clear the previous timeout
    clearTimeout(timeoutId);

    // Set a new timeout
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}
```

## Usage Example

```javascript
// Example: Search input that calls an API
const handleSearch = (query) => {
  console.log('Searching for:', query);
  // API call would go here
};

const debouncedSearch = debounce(handleSearch, 500);

// Simulate user typing
debouncedSearch('j');      // Timeout set
debouncedSearch('ja');     // Previous timeout cleared, new one set
debouncedSearch('jav');    // Previous timeout cleared, new one set
debouncedSearch('java');   // Previous timeout cleared, new one set
// After 500ms of no calls: "Searching for: java" is logged
```

## Advanced Implementation with Options

```javascript
function debounce(func, delay, options = {}) {
  let timeoutId;
  let lastCallTime = 0;
  let lastResult;

  const { leading = false, trailing = true, maxWait } = options;
  let maxWaitTimeoutId;

  return function debounced(...args) {
    const now = Date.now();
    const isFirstCall = lastCallTime === 0;

    // Handle leading edge
    if (leading && isFirstCall) {
      lastResult = func.apply(this, args);
    }

    lastCallTime = now;

    // Clear existing timeouts
    clearTimeout(timeoutId);
    clearTimeout(maxWaitTimeoutId);

    // Handle trailing edge
    if (trailing) {
      timeoutId = setTimeout(() => {
        lastResult = func.apply(this, args);
        lastCallTime = 0;
      }, delay);
    }

    // Handle maxWait
    if (maxWait && !maxWaitTimeoutId) {
      maxWaitTimeoutId = setTimeout(() => {
        lastResult = func.apply(this, args);
        lastCallTime = 0;
        clearTimeout(timeoutId);
      }, maxWait);
    }

    return lastResult;
  };
}
```

## Real-World Examples

### 1. Search Input
```javascript
const searchAPI = (query) => {
  fetch(`/api/search?q=${query}`)
    .then(res => res.json())
    .then(data => console.log(data));
};

const debouncedSearch = debounce(searchAPI, 300);

document.getElementById('searchInput').addEventListener('input', (e) => {
  debouncedSearch(e.target.value);
});
```

### 2. Window Resize
```javascript
const handleResize = () => {
  console.log('Window resized to:', window.innerWidth, 'x', window.innerHeight);
};

const debouncedResize = debounce(handleResize, 250);
window.addEventListener('resize', debouncedResize);
```

### 3. Auto-save Form
```javascript
const saveForm = (formData) => {
  console.log('Saving:', formData);
  // Save to database
};

const debouncedSave = debounce(saveForm, 1000);

document.getElementById('form').addEventListener('input', (e) => {
  const formData = new FormData(e.target.form);
  debouncedSave(Object.fromEntries(formData));
});
```

## Debounce with Cancel Method

```javascript
function debounce(func, delay) {
  let timeoutId;

  const debounced = function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };

  // Add cancel method
  debounced.cancel = () => {
    clearTimeout(timeoutId);
  };

  // Add flush method (execute immediately)
  debounced.flush = function(...args) {
    clearTimeout(timeoutId);
    func.apply(this, args);
  };

  return debounced;
}

// Usage
const debouncedSearch = debounce(handleSearch, 500);
debouncedSearch('test');
debouncedSearch.cancel();  // Cancel pending execution
debouncedSearch.flush();   // Execute immediately
```

## Key Points

| Feature | Description |
|---------|-------------|
| **Delay** | Time to wait after last call before executing |
| **Clears timeout** | Each new call resets the timer |
| **Preserves context** | Uses `.apply(this, args)` to maintain correct `this` |
| **Leading** | Execute on first call immediately |
| **Trailing** | Execute after delay (default) |
| **MaxWait** | Force execution after maximum time |

Choose the basic version for simple cases, or the advanced version when you need more control over execution timing!

