# Thread-Safe Rate Limiter in Go (Token Bucket Algorithm)

I'll implement a comprehensive rate limiter with multiple variations and examples.

## 1. Basic Token Bucket Implementation

```go
package ratelimiter

import (
	"sync"
	"time"
)

// TokenBucket implements a thread-safe rate limiter using the token bucket algorithm
type TokenBucket struct {
	mu              sync.Mutex
	tokens          float64
	maxTokens       float64
	refillRate      float64 // tokens per second
	lastRefillTime  time.Time
}

// NewTokenBucket creates a new token bucket with specified capacity and refill rate
func NewTokenBucket(maxTokens float64, refillRate float64) *TokenBucket {
	return &TokenBucket{
		tokens:         maxTokens,
		maxTokens:      maxTokens,
		refillRate:     refillRate,
		lastRefillTime: time.Now(),
	}
}

// Allow checks if a request can be allowed (non-blocking)
func (tb *TokenBucket) Allow() bool {
	return tb.AllowN(1)
}

// AllowN checks if n tokens can be consumed
func (tb *TokenBucket) AllowN(n float64) bool {
	tb.mu.Lock()
	defer tb.mu.Unlock()

	tb.refill()

	if tb.tokens >= n {
		tb.tokens -= n
		return true
	}
	return false
}

// Wait blocks until a token is available
func (tb *TokenBucket) Wait() {
	tb.WaitN(1)
}

// WaitN blocks until n tokens are available
func (tb *TokenBucket) WaitN(n float64) {
	for {
		tb.mu.Lock()
		tb.refill()

		if tb.tokens >= n {
			tb.tokens -= n
			tb.mu.Unlock()
			return
		}

		// Calculate wait time
		tokensNeeded := n - tb.tokens
		waitTime := time.Duration(float64(time.Second) * tokensNeeded / tb.refillRate)
		tb.mu.Unlock()

		time.Sleep(waitTime)
	}
}

// refill adds tokens based on elapsed time (must be called with lock held)
