Here's a complete implementation with tokenizer, parser, and evaluator:

```python
import re
from enum import Enum, auto
from typing import List, Union

class TokenType(Enum):
    """Token types for the lexer"""
    NUMBER = auto()
    PLUS = auto()
    MINUS = auto()
    MULTIPLY = auto()
    DIVIDE = auto()
    LPAREN = auto()
    RPAREN = auto()
    EOF = auto()

class Token:
    """Represents a single token"""
    def __init__(self, type_: TokenType, value: Union[float, str]):
        self.type = type_
        self.value = value

    def __repr__(self):
        return f"Token({self.type}, {self.value})"

class Lexer:
    """Tokenizes arithmetic expressions"""
    def __init__(self, text: str):
        self.text = text
        self.pos = 0
        self.current_char = self.text[0] if text else None

    def advance(self):
        """Move to the next character"""
        self.pos += 1
        if self.pos < len(self.text):
            self.current_char = self.text[self.pos]
        else:
            self.current_char = None

    def skip_whitespace(self):
        """Skip whitespace characters"""
        while self.current_char is not None and self.current_char.isspace():
            self.advance()

    def read_number(self) -> float:
        """Read a number (integer or float)"""
        num_str = ''
        while self.current_char is not None and (self.current_char.isdigit() or self.current_char == '.'):
            num_str += self.current_char
            self.advance()
        return float(num_str)

    def get_next_token(self) -> Token:
        """Lexical analyzer - break input into tokens"""
        while self.current_char is not None:
            if self.current_char.isspace():
                self.skip_whitespace()
                continue

            if self.current_char.isdigit() or self.current_char == '.':
                return Token(TokenType.NUMBER, self.read_number())

            if self.current_char == '+':
                self.advance()
                return Token(TokenType.PLUS, '+')

            if self.current_char == '-':
                self.advance()
                return Token(TokenType.MINUS, '-')

            if self.current_char == '*':
                self.advance()
                return Token(TokenType.MULTIPLY, '*')

            if self.current_char == '/':
                self.advance()
                return Token(TokenType.DIVIDE, '/')

            if self.current_char == '(':
                self.advance()
                return Token(TokenType.LPAREN, '(')

            if self.current_char == ')':
                self.advance()
                return Token(TokenType.RPAREN, ')')

            raise Exception(f"Invalid character: {self.current_char}")

        return Token(TokenType.EOF, None)

class Parser:
    """Recursive descent parser for arithmetic expressions"""
    def __init__(self, lexer: Lexer):
        self.lexer = lexer
        self.current_token = self.lexer.get_next_token()

    def eat(self, token_type: TokenType):
        """Consume a token of a given type"""
        if self.current_token.type == token_type:
            self.current_token = self.lexer.get_next_token()
        else:
            raise Exception(f"Invalid syntax: expected {token_type}, got {self.current_token.type}")

    def factor(self) -> float:
        """
        factor : NUMBER | LPAREN expr RPAREN
        """
        token = self.current_token

        if token.type == TokenType.NUMBER:
            self.eat(TokenType.NUMBER)
            return token.value

        elif token.type == TokenType.LPAREN:
            self.eat(TokenType.LPAREN)
            result = self.expr()
            self.eat(TokenType.RPAREN)
            return result

        elif token.type == TokenType.MINUS:
            self.eat(TokenType.MINUS)
            return -self.factor()

        elif token.type == TokenType.PLUS:
            self.eat(TokenType.PLUS)
            return self.factor()

        raise Exception(f"Invalid syntax: unexpected token {token}")

    def term(self) -> float:
        """
        term : factor ((MULTIPLY | DIVIDE) factor)*
        Handles * and / with higher precedence than + and -
        """
        result = self.factor()

        while self.current_token.type in (TokenType.MULTIPLY, TokenType.DIVIDE):
            token = self.current_token

            if token.type == TokenType.MULTIPLY:
                self.eat(TokenType.MULTIPLY)
                result *= self.factor()

            elif token.type == TokenType.DIVIDE:
                self.eat(TokenType.DIVIDE)
                divisor = self.factor()
                if divisor == 0:
                    raise Exception("Division by zero")
                result /= divisor

        return result

    def expr(self) -> float:
        """
        expr : term ((PLUS | MINUS) term)*
        Handles + and - with lower precedence than * and /
        """
        result = self.term()

        while self.current_token.type in (TokenType.PLUS, TokenType.MINUS):
            token = self.current_token

            if token.type == TokenType.PLUS:
                self.eat(TokenType.PLUS)
                result += self.term()

            elif token.type == TokenType.MINUS:
                self.eat(TokenType.MINUS)
                result -= self.term()

        return result

    def parse(self) -> float:
        """Parse and evaluate the expression"""
        result = self.expr()
        if self.current_token.type != TokenType.EOF:
            raise Exception("Invalid syntax: unexpected tokens after expression")
        return result

class Calculator:
    """High-level interface for the calculator"""
    def __init__(self):
        pass

    def evaluate(self, expression: str) -> float:
        """Evaluate an arithmetic expression"""
        lexer = Lexer(expression)
        parser = Parser(lexer)
        return parser.parse()

# Example usage and tests
if __name__ == "__main__":
