        ("(2 + 3) * 4", 20),  # Tests parentheses
        ("10 - 2 - 3", 5),  # Tests left associativity
        ("100 / 2 / 5", 10),  # Tests left associativity
        ("((2 + 3) * (4 - 1))", 15),  # Nested parentheses
        ("-5 + 3", -2),  # Unary minus
        ("+10 - 5", 5),  # Unary plus
        ("2.5 + 3.5", 6.0),  # Floating point
        ("1 + 2 * 3 - 4 / 2", 7.0),  # Complex expression
