Memory leaks in event-driven Node.js apps are a classic problem. Here's a systematic approach rather than just throwing tools at it.

## Step 1: Confirm It's Actually a Leak

First, distinguish between a leak and legitimate memory growth:

```javascript
// Add this to get baseline metrics
const v8 = require('v8');
const process = require('process');

function logMemory(label) {
  const heap = v8.getHeapStatistics();
  const mem = process.memoryUsage();
  console.log(`[${label}]`, {
    heapUsed: `${Math.round(mem.heapUsed / 1024 / 1024)}MB`,
    heapTotal: `${Math.round(mem.heapTotal / 1024 / 1024)}MB`,
    external: `${Math.round(mem.external / 1024 / 1024)}MB`,
    rss: `${Math.round(mem.rss / 1024 / 1024)}MB`,
    // This is the key one - objects not yet collected
    heapUsedAfterGC: `${Math.round(heap.used_heap_size / 1024 / 1024)}MB`
  });
}

// Log every 30 seconds
setInterval(() => logMemory('periodic'), 30000);

// Force GC first if you want clean readings
// Run node with --expose-gc flag
if (global.gc) {
  setInterval(() => {
    global.gc();
    logMemory('post-gc');
  }, 60000);
}
```

**What to look for:** If memory grows even *after* GC runs, you have a real leak. If it grows but GC brings it back down, you might just have allocation pressure.

## Step 2: Take Heap Snapshots

```javascript
const v8 = require('v8');
const fs = require('fs');

function takeSnapshot(filename) {
  // This is the built-in way - no extra dependencies
  const snapshotStream = v8.writeHeapSnapshot();
  console.log(`Snapshot written to: ${snapshotStream}`);
}

// Expose via an endpoint so you can trigger on demand
const http = require('http');
http.createServer((req, res) => {
  if (req.url === '/snapshot') {
    takeSnapshot();
    res.end('Snapshot taken');
  }
}).listen(9229);
```

**The workflow that actually works:**
1. Take snapshot at startup (baseline)
2. Run under load for 30-60 minutes
3. Take second snapshot
4. Take third snapshot 30 minutes later
5. Compare snapshots 2 and 3 in Chrome DevTools

```
# Load snapshots in Chrome DevTools:
# chrome://inspect -> Open dedicated DevTools -> Memory tab
# Load snapshot files, then use "Comparison" view
```

**In the comparison view, sort by "Delta" - objects that keep growing between snapshots are your suspects.**

## Step 3: Identify Common Leak Patterns

### Pattern 1: Event Listener Accumulation
```javascript
// BAD - classic leak
class DataProcessor extends EventEmitter {
  constructor(eventBus) {
    super();
    // This listener is added every time a new DataProcessor is created
    // but never removed when the processor is destroyed
    eventBus.on('data', (data) => {
      this.process(data);
    });
  }
}

// GOOD
class DataProcessor extends EventEmitter {
  constructor(eventBus) {
    super();
    // Keep reference so we can remove it
    this.dataHandler = (data) => this.process(data);
    eventBus.on('data', this.dataHandler);
  }

  destroy() {
    // Always clean up
    this.eventBus.off('data', this.dataHandler);
    this.removeAllListeners();
  }
}

// Also - watch for this warning, it's telling you something real:
// MaxListenersExceededWarning: Possible EventEmitter memory leak detected
// Don't just increase the limit - fix the underlying issue
emitter.setMaxListeners(100); // This is hiding the problem, not fixing it
```

### Pattern 2: Closures Holding References
```javascript
// BAD - the closure captures the entire request object
function setupRequestHandler(app) {
  app.on('request', (req, res) => {
    const requestData = extractData(req); // req might be huge

    someAsyncOperation().then(() => {
      // req is still referenced here, keeping it alive
      // even if we only need requestData
      logRequest(req);
    });
  });
}

// GOOD - only capture what you need
function setupRequestHandler(app) {
  app.on('request', (req, res) => {
    const requestData = extractData(req);
    const requestId = req.id; // just the primitive
    const method = req.method; // just the primitive

    someAsyncOperation().then(() => {
      logRequest({ requestId, method }); // req can be GC'd
    });
  });
}
```

### Pattern 3: Unbounded Caches
```javascript
// BAD - grows forever
const cache = new Map();

function processRequest(key, data) {
  if (cache.has(key)) return cache.get(key);
  const result = expensiveOperation(data);
  cache.set(key, result); // never evicted
  return result;
}

// GOOD - use WeakMap where possible, or implement eviction
const cache = new Map();
const MAX_CACHE_SIZE = 1000;

function processRequest(key, data) {
  if (cache.has(key)) return cache.get(key);

  const result = expensiveOperation(data);

  // Simple LRU-ish eviction
  if (cache.size >= MAX_CACHE_SIZE) {
    const firstKey = cache.keys().next().value;
    cache.delete(firstKey);
  }

  cache.set(key, result);
  return result;
}

// Or use WeakMap when keys are objects - GC handles cleanup automatically
const weakCache = new WeakMap();
function processObject(obj) {
  if (weakCache.has(obj)) return weakCache.get(obj);
  const result = expensiveOperation(obj);
  weakCache.set(obj, result); // automatically cleaned up when obj is GC'd
  return result;
}
```

### Pattern 4: Timers and Intervals Not Cleared
```javascript
// BAD
class ConnectionManager {
  constructor() {
    // If ConnectionManager is recreated, old interval keeps running
    // and holds reference to old instance
    setInterval(() => this.checkConnections(), 5000);
  }
}

// GOOD
class ConnectionManager {
  constructor() {
    this.checkInterval = setInterval(() => this.checkConnections(), 5000);
  }

  destroy() {
    clearInterval(this.checkInterval);
  }
}

// Also watch for setTimeout in recursive patterns
function badRecursiveTimer() {
  doWork();
  setTimeout(badRecursiveTimer, 1000); // if doWork throws, this still fires
}

function goodRecursiveTimer() {
  try {
    doWork();
  } finally {
    // Or use setInterval and clear it on error
    setTimeout(goodRecursiveTimer, 1000);
  }
}
```

### Pattern 5: Promise Chains Accumulating
```javascript
// BAD - if promises reject and aren't caught, they accumulate
const pendingOperations = [];

function startOperation(data) {
  const promise = someAsyncWork(data);
  pendingOperations.push(promise); // never cleaned up
  return promise;
}

// GOOD
const pendingOperations = new Set();

function startOperation(data) {
  const promise = someAsyncWork(data)
    .finally(() => {
      pendingOperations.delete(promise); // clean up when done
    });
  pendingOperations.add(promise);
  return promise;
}
```

## Step 4: Use Clinic.js for Deeper Analysis

```bash
npm install -g clinic

# Heap profiler - shows allocation over time
clinic heapprofiler -- node your-app.js

# Flame graphs for CPU (sometimes related to leak symptoms)

